framework_css:
/*
  Industrial Tarps & Protective Covers - Global Framework Styles
  Visual style inspired by early-2000s corporate/catalog design with
  skeuomorphic gradients, glossy tabs, and dense information layout.
*/

:root {
  /* Core color system (from design & brief) */
  --color-primary-red: #CC3333;
  --color-primary-red-light: #E24B4B;
  --color-primary-red-dark: #B22222;

  --color-primary-indigo: #4A3FA0;
  --color-primary-indigo-dark: #2D2C7F;

  --color-secondary-lavender: #D7D5FF;
  --color-secondary-blue: #3366CC;

  --color-white: #FFFFFF;
  --color-black: #000000;
  --color-neutral-border: #CCCCCC;
  --color-neutral-muted: #EEEEEE;

  /* Semantic colors (for future use) */
  --color-semantic-success: #4CAF50;
  --color-semantic-error: #D32F2F;
  --color-semantic-warning: #FFC107;
  --color-semantic-info: #1976D2;

  /* Typography */
  --font-family-heading: Georgia, "Times New Roman", serif;
  --font-family-body: "Times New Roman", Times, serif;
  --font-family-ui: Arial, Helvetica, sans-serif;

  --font-size-body: 13px;
  --font-size-small: 11px;
  --font-size-h1: 26px;
  --font-size-h2: 20px;
  --font-size-h3: 16px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.4;

  /* Spacing scale (approx. 8px base) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 12px;
  --space-md: 16px;
  --space-lg: 24px;
  --space-xl: 32px;

  /* Radii */
  --radius-pill: 24px;
}

* {
  box-sizing: border-box;
}

body.site {
  margin: 0;
  padding: 0;
  background-color: var(--color-white);
  color: var(--color-black);
  font-family: var(--font-family-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
}

.page-wrapper {
  max-width: 980px;
  margin: 0 auto;
  background-color: var(--color-white);
}

/* Header */

.site-header {
  padding-top: var(--space-sm);
}

.logo-bar {
  display: flex;
  align-items: center;
  padding: 0 var(--space-md) var(--space-xs);
  border-bottom: 3px solid var(--color-primary-red);
}

.logo-mark {
  width: 120px;
  height: 80px;
  margin-right: var(--space-sm);
  border-radius: 60px;
  background:
    radial-gradient(circle at 30% 30%, #F5F4FF 0%, var(--color-secondary-lavender) 35%, var(--color-primary-indigo) 65%, var(--color-primary-indigo-dark) 100%);
}

.site-identity {
  padding-top: var(--space-xxs);
}

.site-name {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-h1);
  font-weight: bold;
  color: var(--color-primary-indigo);
  letter-spacing: 0.02em;
}

.site-tagline {
  margin-top: 2px;
  font-family: var(--font-family-body);
  font-size: var(--font-size-small);
  color: var(--color-primary-red);
}

/* Top navigation - glossy red tab bar */

.top-nav {
  margin: var(--space-sm) var(--space-md) 0;
  background: linear-gradient(to bottom, var(--color-primary-red-light) 0%, var(--color-primary-red) 50%, var(--color-primary-red-dark) 100%);
  border-radius: var(--radius-pill) var(--radius-pill) 0 0;
}

.top-nav-list {
  list-style: none;
  margin: 0;
  padding: 0 var(--space-xxs);
  display: flex;
  flex-wrap: wrap;
}

.top-nav-item {
  margin: 0;
}

.top-nav-item a {
  display: block;
  padding: 8px var(--space-md);
  font-family: var(--font-family-ui);
  font-size: var(--font-size-body);
  font-weight: bold;
  color: var(--color-white);
  text-decoration: none;
  white-space: nowrap;
  border-left: 1px solid rgba(255, 255, 255, 0.7);
}

.top-nav-item:first-child a {
  border-left: none;
}

.top-nav-item a:hover,
.top-nav-item a:focus {
  background-color: var(--color-primary-red-dark);
  text-decoration: underline;
}

/* Layout */

.layout {
  display: flex;
  align-items: stretch;
}

/* Sidebar - strong left navigation stack */

.sidebar {
  width: 220px;
  background-color: var(--color-secondary-lavender);
  border-right: 1px solid var(--color-neutral-border);
  padding-bottom: var(--space-lg);
}

.sidebar-header {
  background: linear-gradient(to bottom, var(--color-primary-red-light) 0%, var(--color-primary-red) 100%);
  color: var(--color-white);
  font-family: var(--font-family-ui);
  font-weight: bold;
  font-size: var(--font-size-body);
  text-transform: uppercase;
  padding: 6px var(--space-sm);
}

.sidebar-section {
  padding: var(--space-sm) var(--space-xs) 0;
}

.sidebar-title {
  margin: 0 0 var(--space-xs);
  padding: 6px var(--space-sm);
  font-family: var(--font-family-ui);
  font-size: var(--font-size-body);
  font-weight: bold;
  color: var(--color-white);
  background: linear-gradient(to bottom, #6D63D7 0%, var(--color-primary-indigo) 40%, var(--color-primary-indigo-dark) 100%);
  border-radius: 0 var(--radius-pill) var(--radius-pill) 0;
}

.sidebar-list {
  list-style: none;
  margin: 0 0 var(--space-sm) 0;
  padding: 0 0 var(--space-xs) var(--space-sm);
}

.sidebar-list li {
  margin: 2px 0;
  font-size: 12px;
  color: var(--color-secondary-blue);
}

/* Main content area */

.content-area {
  flex: 1;
  padding: var(--space-md) var(--space-xl) var(--space-lg) var(--space-lg);
  min-height: 420px;
}

.content-area h1,
.content-area h2,
.content-area h3 {
  font-family: var(--font-family-heading);
  color: var(--color-primary-indigo);
}

.content-area h1 {
  font-size: var(--font-size-h2);
  margin-top: 0;
}

.content-area p {
  margin: 0 0 var(--space-xs);
}

.content-area ul {
  margin-top: 0;
}

/* Generic link styling (content & footer) */

a {
  color: var(--color-secondary-blue);
}

a:hover,
a:focus {
  text-decoration: underline;
}

/* Footer */

.site-footer {
  margin-top: var(--space-lg);
  border-top: 3px solid var(--color-primary-red);
  background: linear-gradient(to top, var(--color-neutral-muted) 0%, var(--color-white) 55%);
  font-family: var(--font-family-ui);
}

.footer-inner {
  padding: var(--space-sm) var(--space-md) var(--space-md);
}

.footer-nav-list {
  list-style: none;
  margin: 0 0 var(--space-xxs);
  padding: 0;
  display: flex;
  flex-wrap: wrap;
}

.footer-nav-item {
  margin-right: var(--space-xs);
  padding-right: var(--space-xs);
  border-right: 1px solid var(--color-neutral-border);
}

.footer-nav-item:last-child {
  margin-right: 0;
  padding-right: 0;
  border-right: none;
}

.footer-nav-item a {
  font-size: var(--font-size-small);
  text-decoration: none;
}

.footer-nav-item a:hover,
.footer-nav-item a:focus {
  text-decoration: underline;
}

.footer-meta {
  font-size: var(--font-size-small);
  color: #666666;
}

.footer-meta .footer-note {
  margin-left: var(--space-xs);
}

/* Optional user avatar dropdown styles (for future special access pages) */

.user-menu {
  position: relative;
  margin-left: auto;
}

.user-menu-toggle {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: linear-gradient(to bottom, var(--color-primary-indigo) 0%, var(--color-primary-indigo-dark) 100%);
  color: var(--color-white);
  font-family: var(--font-family-ui);
  font-size: 14px;
  text-decoration: none;
}

.user-menu-dropdown {
  position: absolute;
  top: 36px;
  right: 0;
  min-width: 160px;
  background-color: var(--color-white);
  border: 1px solid var(--color-neutral-border);
  padding: var(--space-xs) 0;
  list-style: none;
  margin: 0;
  display: none;
  z-index: 10;
}

.user-menu-dropdown li {
  margin: 0;
}

.user-menu-dropdown a {
  display: block;
  padding: 4px var(--space-sm);
  font-family: var(--font-family-ui);
  font-size: var(--font-size-body);
  color: var(--color-black);
  text-decoration: none;
}

.user-menu-dropdown a:hover,
.user-menu-dropdown a:focus {
  background-color: var(--color-secondary-lavender);
}

/* Show dropdown on hover or focus-within for non-JS behavior */

.user-menu:hover .user-menu-dropdown,
.user-menu:focus-within .user-menu-dropdown {
  display: block;
}

/* Basic responsiveness without changing the classic feel */

@media (max-width: 900px) {
  .page-wrapper {
    max-width: 100%;
  }

  .layout {
    flex-direction: column;
  }

  .sidebar {
    width: 100%;
    border-right: none;
    border-bottom: 1px solid var(--color-neutral-border);
  }

  .content-area {
    padding: var(--space-md);
  }
}

@media (max-width: 640px) {
  .logo-bar {
    flex-direction: column;
    align-items: flex-start;
  }

  .logo-mark {
    margin-bottom: var(--space-xs);
  }

  .top-nav {
    border-radius: 0;
    margin-left: 0;
    margin-right: 0;
  }
}
